<script setup>import {reactive,ref} from 'vue';import {useRouter} from 'vue-router';import {useAuthStore} from '../stores';const form=reactive({username:'admin',password:''}),loading=ref(false),error=ref(''),router=useRouter(),auth=useAuthStore();async function submit(){error.value='';loading.value=true;try{await auth.login(form);router.push('/dashboard');}catch(e){error.value=e.response?.data?.message||'登录失败，请检查账号和密码';}finally{loading.value=false;}}</script>
<template><div class="login-page"><div class="login-art"><div class="login-brand">PetCare Admin</div><div class="orbit"><div class="pet-face">⌁</div></div><div><p class="eyebrow">CARE WITH CLARITY</p><h1>让每一份宠物健康数据<br>都清晰、可信、可追溯</h1><p>面向运营团队的安全管理工作台</p></div></div><div class="login-panel"><form @submit.prevent="submit"><div class="mobile-brand">PetCare Admin</div><p class="eyebrow">欢迎回来</p><h2>登录管理控制台</h2><p class="muted">使用管理员账号继续</p><label>管理员账号<el-input v-model="form.username" size="large" placeholder="请输入账号"/></label><label>密码<el-input v-model="form.password" size="large" type="password" show-password placeholder="请输入密码"/></label><el-alert v-if="error" :title="error" type="error" :closable="false"/><el-button native-type="submit" type="primary" size="large" :loading="loading">安全登录</el-button><small class="security-note">管理员操作将被完整记录</small></form></div></div></template>
